						montoNew.PREVISIONES.Add(prevNew);
						NomadEnvironment.GetTrace().Info("montoFinal: " + montoNew.SerializeAll());
						NomadEnvironment.GetCurrentTransaction().SaveRefresh(montoNew);
	 				}	
	 			}
	 		}		 			
	 	}  	 	
	}
}

